parameters.workflowJson:
={{ JSON.stringify({
  id: 'inline-versimpelaar-tool',
  name: 'Inline Versimpelaar Tool',
  nodes: [
    {
      id: 'execTrigger',
      name: 'When Executed by Another Workflow',
      type: 'n8n-nodes-base.executeWorkflowTrigger',
      typeVersion: 1,
      position: [-420, 120],
      parameters: {}
    },
    {
      id: 'toolCode1',
      name: 'Prepare Tool Request',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [-180, 120],
      parameters: {
        jsCode: "const input = $json || {};\nconst text = String(input.text || input.input || input.prompt || '').trim();\nif (!text) throw new Error('Tool input moet veld text bevatten');\nconst token = String($env.N8N_WEBHOOK_TOKEN || '').trim();\nif (!token) throw new Error('N8N_WEBHOOK_TOKEN ontbreekt');\nreturn [{ json: { text, token } }];"
      }
    },
    {
      id: 'toolHttp',
      name: 'Call Versimpelaar Webhook',
      type: 'n8n-nodes-base.httpRequest',
      typeVersion: 4.2,
      position: [80, 120],
      parameters: {
        method: 'POST',
        url: '=http://n8n:5678/webhook/versimpelaar',
        sendHeaders: true,
        headerParameters: {
          parameters: [
            { name: 'Content-Type', value: 'application/json' },
            { name: 'x-govchat-token', value: '={{$json.token}}' }
          ]
        },
        sendBody: true,
        specifyBody: 'json',
        jsonBody: '={{ JSON.stringify({ text: $json.text }) }}',
        options: { timeout: 120000 }
      }
    },
    {
      id: 'toolCode2',
      name: 'Build Tool Response',
      type: 'n8n-nodes-base.code',
      typeVersion: 2,
      position: [320, 120],
      parameters: {
        jsCode: "const text = String($json.text || $json.output || $json.result || '').trim();\nif (!text) throw new Error('Versimpelaar gaf geen tekst terug');\nreturn [{ json: { response: text } }];"
      }
    }
  ],
  connections: {
    'When Executed by Another Workflow': { main: [[{ node: 'Prepare Tool Request', type: 'main', index: 0 }]] },
    'Prepare Tool Request': { main: [[{ node: 'Call Versimpelaar Webhook', type: 'main', index: 0 }]] },
    'Call Versimpelaar Webhook': { main: [[{ node: 'Build Tool Response', type: 'main', index: 0 }]] }
  }
}) }}
